/* ─────────────────────────────────────────────
   UTILITY + SHARED COMPONENTS
───────────────────────────────────────────── */
const fmtN = n => n >= 1000 ? (n/1000).toFixed(1)+"K" : String(n);
const fmtDate = d => d.toLocaleDateString("en-CA",{weekday:"short",month:"short",day:"numeric"});
const fmtDur = m => m >= 60 ? `${Math.floor(m/60)}h${m%60>0?" "+m%60+"m":""}` : `${m}m`;

const Avatar = ({ initials, belt="white", size=36, photo=null, style={} }) => {
  const bc = BELT_COLOR[belt] || "#E8E8E8";
  return (
    <div style={{ width:size, height:size, borderRadius:"50%", background: photo?"transparent":C.bgElevated, border:`2px solid ${bc}`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, overflow:"hidden", boxShadow:`0 0 8px ${bc}40`, ...style }}>
      {photo ? <img src={photo} style={{width:"100%",height:"100%",objectFit:"cover"}}/> :
        <span style={{ color:bc, fontFamily:"'Oswald',sans-serif", fontSize:size*0.33, fontWeight:700, letterSpacing:0.5 }}>{initials}</span>}
    </div>
  );
};

const Tag = ({ label, color=C.muted }) => (
  <span style={{ background:`${color}20`, border:`1px solid ${color}40`, color, borderRadius:4, padding:"2px 7px", fontSize:10, fontFamily:"'Oswald',sans-serif", letterSpacing:0.5, fontWeight:600 }}>#{label}</span>
);

const Divider = ({ color=C.border }) => <div style={{ height:1, background:color, margin:"12px 0" }}/>;

const Badge = ({ count, color=C.red }) => count > 0 ? (
  <div style={{ position:"absolute", top:-4, right:-4, background:color, borderRadius:10, minWidth:16, height:16, display:"flex", alignItems:"center", justifyContent:"center", padding:"0 4px", border:`2px solid ${C.bg}` }}>
    <span style={{ color:C.white, fontSize:9, fontWeight:800, fontFamily:"'Oswald',sans-serif" }}>{count > 99 ? "99+" : count}</span>
  </div>
) : null;

const Pill = ({ label, active, onClick, color=C.red }) => (
  <button onClick={onClick} style={{ background: active ? `${color}20` : "transparent", border:`1px solid ${active?color:C.border}`, color: active ? color : C.muted, borderRadius:20, padding:"5px 12px", fontSize:11, fontFamily:"'Oswald',sans-serif", fontWeight:600, letterSpacing:0.5, cursor:"pointer", transition:"all 0.2s", flexShrink:0 }}>{label}</button>
);

const Toggle = ({ on, onToggle, label, sublabel }) => (
  <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"12px 0" }} onClick={onToggle}>
    <div>
      <div style={{ color:C.white, fontSize:13, fontWeight:500 }}>{label}</div>
      {sublabel && <div style={{ color:C.muted, fontSize:11, marginTop:2 }}>{sublabel}</div>}
    </div>
    <div style={{ width:44, height:24, borderRadius:12, background: on ? C.red : C.bgElevated, border:`1px solid ${on?C.red:C.border}`, position:"relative", cursor:"pointer", transition:"all 0.3s" }}>
      <div style={{ position:"absolute", top:3, left: on?22:3, width:16, height:16, borderRadius:"50%", background: on?C.white:C.muted, transition:"left 0.3s" }}/>
    </div>
  </div>
);

const Overlay = ({ onClose, title, children, rightAction }) => (
  <div style={{ position:"absolute", inset:0, background:C.bg, zIndex:100, display:"flex", flexDirection:"column", animation:"slideUp 0.25s ease" }}>
    <style>{`@keyframes slideUp{from{transform:translateY(20px);opacity:0}to{transform:translateY(0);opacity:1}}`}</style>
    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"14px 16px", borderBottom:`1px solid ${C.border}` }}>
      <button onClick={onClose} style={{ background:"none", border:"none", cursor:"pointer", color:C.muted, padding:4 }}>
        <Icon name="chevL" size={22} color={C.offWhite}/>
      </button>
      <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:15, fontWeight:700, letterSpacing:1 }}>{title}</span>
      <div style={{ width:30 }}>{rightAction || null}</div>
    </div>
    <div style={{ flex:1, overflowY:"auto" }}>{children}</div>
  </div>
);

/* ─────────────────────────────────────────────
   POST CARD COMPONENT
───────────────────────────────────────────── */
const PostCard = ({ post, onComment, onLikeToggle, onSaveToggle, onOpenPost }) => {
  const [respected, setRespected] = useState(post.liked);
  const [saved, setSaved] = useState(post.saved);
  const [respectCount, setRespectCount] = useState(post.likes);
  const [showOss, setShowOss] = useState(false);
  const [showPlus, setShowPlus] = useState(false);
  const typeColors = { technique:C.red, insight:C.gold, story:C.teal, milestone:C.purple };
  const typeColor = typeColors[post.type] || C.muted;

  const handleRespect = () => {
    const next = !respected;
    setRespected(next);
    setRespectCount(c => next ? c+1 : c-1);
    onLikeToggle && onLikeToggle(post.id, next);
  };
  const handleDoubleTap = () => {
    // Always respect on double-tap (never un-respect via double-tap)
    if (!respected) {
      setRespected(true);
      setRespectCount(c => c+1);
      onLikeToggle && onLikeToggle(post.id, true);
    }
    setShowOss(true);
    setShowPlus(true);
    setTimeout(()=>setShowOss(false), 800);
    setTimeout(()=>setShowPlus(false), 900);
  };

  return (
    <div style={{ background:C.bgCard, borderBottom:`1px solid ${C.border}`, padding:"14px 16px" }}>
      {/* Header */}
      <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:10 }}>
        <Avatar initials={post.avatar} belt={post.belt} size={38}/>
        <div style={{ flex:1 }}>
          <div style={{ display:"flex", alignItems:"center", gap:5 }}>
            <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:13, fontWeight:700 }}>{post.user}</span>
            {post.verified && <Icon name="verified" size={13} color={C.gold}/>}
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:6, marginTop:1 }}>
            <span style={{ color:C.muted, fontSize:10 }}>{post.handle}</span>
            <span style={{ color:C.border, fontSize:10 }}>•</span>
            <span style={{ color:C.muted, fontSize:10 }}>{post.timeAgo}</span>
            <span style={{ background:`${typeColor}20`, border:`1px solid ${typeColor}40`, color:typeColor, borderRadius:3, padding:"1px 5px", fontSize:9, fontFamily:"'Oswald',sans-serif", fontWeight:700, letterSpacing:0.5 }}>{post.type?.toUpperCase()}</span>
          </div>
        </div>
        <button style={{ background:"none", border:"none", cursor:"pointer", color:C.muted }}>
          <Icon name="more" size={18} color={C.muted}/>
        </button>
      </div>

      {/* Body */}
      <div onDoubleClick={handleDoubleTap} onClick={()=>!post.mediaType && onOpenPost&&onOpenPost(post)} style={{ position:"relative", cursor: post.mediaType ? "default" : "pointer" }}>
        {post.title && <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:15, fontWeight:700, marginBottom:5, lineHeight:1.3, borderLeft:`3px solid ${post.accent||typeColor}`, paddingLeft:8 }}>{post.title}</div>}
        <p style={{ color:C.offWhite, fontSize:13, lineHeight:1.6, margin:"0 0 10px" }}>{post.content}</p>
        {post.mediaType === "video" && <VideoPlayer post={post}/>}
        {showOss && (
          <div style={{ position:"absolute", inset:0, display:"flex", alignItems:"center", justifyContent:"center", pointerEvents:"none" }}>
            <style>{`@keyframes ossPop{0%{transform:scale(0.4) rotate(-8deg);opacity:1}55%{transform:scale(1.15) rotate(3deg);opacity:1}100%{transform:scale(1) rotate(0deg);opacity:0}}
            @keyframes plusFloat{0%{transform:translateY(0);opacity:1}100%{transform:translateY(-40px);opacity:0}}`}</style>
            <span style={{ fontFamily:"'Oswald',sans-serif", fontSize:52, fontWeight:900, color:C.red, letterSpacing:4, textShadow:`0 0 30px ${C.redGlow}`, animation:"ossPop 0.8s ease forwards" }}>OSS!</span>
            {showPlus && <span style={{ position:"absolute", top:"25%", right:"25%", fontFamily:"'Oswald',sans-serif", fontSize:20, fontWeight:900, color:C.red, animation:"plusFloat 0.9s ease forwards" }}>+1</span>}
          </div>
        )}
      </div>

      {/* Tags */}
      {post.tags?.length > 0 && (
        <div style={{ display:"flex", flexWrap:"wrap", gap:5, marginBottom:12 }}>
          {post.tags.map(t => <Tag key={t} label={t} color={post.accent||typeColor}/>)}
        </div>
      )}

      {/* BJJ Action Row */}
      <div style={{ display:"flex", alignItems:"center", borderTop:`1px solid ${C.border}`, paddingTop:10 }}>

        {/* Respect */}
        <button onClick={handleRespect} style={{ flex:1, background:"none", border:"none", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:3, padding:"4px 0" }}>
          <div style={{ position:"relative" }}>
            <Icon name="fist" size={18} color={respected ? C.red : C.muted}/>
            {respected && <div style={{ position:"absolute", inset:-2, borderRadius:"50%", background:`${C.red}20`, animation:"respectPulse 0.3s ease" }}/>}
          </div>
          <span style={{ color:respected?C.red:C.muted, fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700, letterSpacing:0.3 }}>{fmtN(respectCount)}</span>
        </button>

        {/* Drill This */}
        <button onClick={()=>onComment&&onComment(post)} style={{ flex:1, background:"none", border:"none", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:3, padding:"4px 0" }}>
          <Icon name="drill" size={18} color={C.muted}/>
          <span style={{ color:C.muted, fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700, letterSpacing:0.3 }}>{fmtN(post.comments)}</span>
        </button>

        {/* Share */}
        <button style={{ flex:1, background:"none", border:"none", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:3, padding:"4px 0" }}>
          <Icon name="share" size={18} color={C.muted}/>
          <span style={{ color:C.muted, fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700, letterSpacing:0.3 }}>{fmtN(post.shares)}</span>
        </button>

        {/* Save */}
        <button onClick={()=>{setSaved(s=>!s); onSaveToggle&&onSaveToggle(post.id,!saved)}} style={{ flex:1, background:"none", border:"none", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:3, padding:"4px 0" }}>
          <Icon name={saved?"bookmarkF":"bookmark"} size={18} color={saved?C.gold:C.muted}/>
          <span style={{ color:saved?C.gold:C.muted, fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700, letterSpacing:0.3 }}>{fmtN(post.saves)}</span>
        </button>

      </div>
      <style>{`@keyframes respectPulse{0%{transform:scale(0);opacity:0.8}100%{transform:scale(2.5);opacity:0}}`}</style>
    </div>
  );
};

/* ─────────────────────────────────────────────
   STORY VIEWER
───────────────────────────────────────────── */
const StoryViewer = ({ stories, startIndex, onClose }) => {
  const [idx, setIdx] = useState(startIndex);
  const [progress, setProgress] = useState(0);
  const [paused, setPaused] = useState(false);
  const DURATION = 5000;
  const story = stories[idx];
  const bc = BELT_COLOR[story?.belt] || C.red;

  const STORY_CONTENT = [
    { bg:`linear-gradient(160deg,#1a0a0a,#3a0a12)`, emoji:"🦵", caption:"Inside heel hook setup — foot angle is EVERYTHING. Don't rush the finish." },
    { bg:`linear-gradient(160deg,#0a0a1a,#1a0a3a)`, emoji:"🧠", caption:"The mat is a mirror. Whatever you avoid out there, you're avoiding in here too." },
    { bg:`linear-gradient(160deg,#0a1a0a,#0a2a1a)`, emoji:"💪", caption:"6 months in. First time I survived a full round with a purple. Progress is real." },
    { bg:`linear-gradient(160deg,#1a1a0a,#2a1a0a)`, emoji:"📖", caption:"Lapel guard breakdown dropping tomorrow. 3 years of notes. Get ready." },
    { bg:`linear-gradient(160deg,#1a0a1a,#2a0a2a)`, emoji:"🏆", caption:"500 days. The number means nothing. The identity means everything." },
    { bg:`linear-gradient(160deg,#0a1a1a,#0a2a2a)`, emoji:"🎯", caption:"Comp prep is 80% mental. The body already knows what to do." },
  ];
  const content = STORY_CONTENT[idx % STORY_CONTENT.length];

  useEffect(() => {
    if(paused) return;
    setProgress(0);
    const start = Date.now();
    const tick = setInterval(() => {
      const elapsed = Date.now() - start;
      const p = Math.min((elapsed / DURATION) * 100, 100);
      setProgress(p);
      if(p >= 100) {
        clearInterval(tick);
        if(idx < stories.length - 1) setIdx(i => i + 1);
        else onClose();
      }
    }, 30);
    return () => clearInterval(tick);
  }, [idx, paused]);

  const goNext = () => { if(idx < stories.length-1) setIdx(i=>i+1); else onClose(); };
  const goPrev = () => { if(idx > 0) setIdx(i=>i-1); };

  return (
    <div style={{ position:"absolute", inset:0, zIndex:400, background:content.bg, display:"flex", flexDirection:"column" }}
      onClick={e => { const x = e.clientX / e.currentTarget.offsetWidth; x < 0.35 ? goPrev() : goNext(); }}>
      <style>{`@keyframes storyIn{from{opacity:0;transform:scale(1.03)}to{opacity:1;transform:scale(1)}}`}</style>

      {/* Progress bars */}
      <div style={{ display:"flex", gap:3, padding:"14px 12px 8px", flexShrink:0 }}>
        {stories.map((_, i) => (
          <div key={i} style={{ flex:1, height:2, borderRadius:1, background:"rgba(255,255,255,0.25)", overflow:"hidden" }}>
            <div style={{ height:"100%", borderRadius:1, background:C.white, width: i < idx ? "100%" : i === idx ? `${progress}%` : "0%", transition: i === idx ? "none" : "none" }}/>
          </div>
        ))}
      </div>

      {/* Header */}
      <div style={{ display:"flex", alignItems:"center", gap:10, padding:"8px 14px", flexShrink:0 }}>
        <div style={{ padding:2, borderRadius:"50%", background:`linear-gradient(135deg,${C.red},${C.gold})` }}>
          <Avatar initials={story.avatar} belt={story.belt} size={36}/>
        </div>
        <div style={{ flex:1 }}>
          <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:13, fontWeight:700 }}>{story.user}</span>
          <span style={{ color:"rgba(255,255,255,0.5)", fontSize:10, marginLeft:8 }}>now</span>
        </div>
        <button onClick={e=>{e.stopPropagation();onClose();}} style={{ background:"none", border:"none", cursor:"pointer" }}>
          <Icon name="x" size={20} color="rgba(255,255,255,0.8)"/>
        </button>
      </div>

      {/* Content */}
      <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", animation:"storyIn 0.3s ease" }}>
        <div style={{ width:100, height:100, borderRadius:"50%", background:"rgba(255,255,255,0.08)", border:`2px solid ${bc}40`, display:"flex", alignItems:"center", justifyContent:"center", marginBottom:28 }}>
          <span style={{ fontSize:44 }}>{content.emoji}</span>
        </div>
        <div style={{ width:8, height:8, borderRadius:"50%", background:bc, marginBottom:18, boxShadow:`0 0 12px ${bc}` }}/>
        <p style={{ color:C.white, fontSize:15, lineHeight:1.7, textAlign:"center", maxWidth:280, padding:"0 20px", textShadow:"0 1px 8px rgba(0,0,0,0.5)" }}>{content.caption}</p>
      </div>

      {/* Bottom actions */}
      <div style={{ padding:"0 16px 32px", display:"flex", gap:10 }} onClick={e=>e.stopPropagation()}>
        <div style={{ flex:1, background:"rgba(255,255,255,0.1)", borderRadius:24, display:"flex", alignItems:"center", padding:"10px 14px", gap:8 }}>
          <input placeholder="Reply to story..." style={{ flex:1, background:"none", border:"none", color:C.white, fontSize:13, outline:"none" }}/>
        </div>
        <button style={{ background:"rgba(255,255,255,0.1)", border:"none", borderRadius:"50%", width:44, height:44, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <Icon name="fist" size={18} color={C.white}/>
        </button>
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────────
   VIDEO PLAYER
───────────────────────────────────────────── */
const VideoPlayer = ({ post }) => {
  const [playing, setPlaying] = useState(false);
  const [playProgress, setPlayProgress] = useState(0);
  const [finished, setFinished] = useState(false);
  const intervalRef = useRef(null);
  const DURATION = 18; // seconds simulated
  const bc = post.accent || C.red;

  const GRADIENTS = [
    `linear-gradient(160deg, #0d0408 0%, #1a0610 50%, #0d0408 100%)`,
    `linear-gradient(160deg, #04080d 0%, #061018 50%, #04080d 100%)`,
    `linear-gradient(160deg, #080d04 0%, #101804 50%, #080d04 100%)`,
  ];
  const grad = GRADIENTS[post.id % GRADIENTS.length];

  const togglePlay = (e) => {
    e.stopPropagation();
    if(finished){ setPlayProgress(0); setFinished(false); setPlaying(true); return; }
    if(playing){
      clearInterval(intervalRef.current);
      setPlaying(false);
    } else {
      setPlaying(true);
      intervalRef.current = setInterval(() => {
        setPlayProgress(p => {
          if(p >= 100){ clearInterval(intervalRef.current); setPlaying(false); setFinished(true); return 100; }
          return p + (100 / (DURATION * 20));
        });
      }, 50);
    }
  };

  useEffect(() => () => clearInterval(intervalRef.current), []);

  const elapsed = Math.floor((playProgress / 100) * DURATION);
  const remaining = DURATION - elapsed;
  const fmt = s => `${Math.floor(s/60)}:${String(s%60).padStart(2,"0")}`;

  return (
    <div style={{ position:"relative", borderRadius:10, overflow:"hidden", marginBottom:10, background:grad }} onClick={togglePlay}>
      <style>{`@keyframes ripple{0%{transform:scale(1);opacity:0.6}100%{transform:scale(2.5);opacity:0}}`}</style>

      {/* Simulated mat texture overlay */}
      <div style={{ height:180, display:"flex", alignItems:"center", justifyContent:"center", position:"relative" }}>
        {/* Animated lines suggesting mat */}
        <div style={{ position:"absolute", inset:0, opacity:0.15 }}>
          {[...Array(6)].map((_,i) => (
            <div key={i} style={{ position:"absolute", left:`${i*20}%`, top:0, bottom:0, width:1, background:bc }}/>
          ))}
          {[...Array(4)].map((_,i) => (
            <div key={i} style={{ position:"absolute", top:`${i*33}%`, left:0, right:0, height:1, background:bc }}/>
          ))}
        </div>

        {/* Belt color accent */}
        <div style={{ position:"absolute", top:12, left:12 }}>
          <div style={{ width:24, height:8, borderRadius:2, background:bc, opacity:0.8 }}/>
        </div>

        {/* Play button */}
        <div style={{ position:"relative", display:"flex", alignItems:"center", justifyContent:"center" }}>
          {playing && <div style={{ position:"absolute", width:60, height:60, borderRadius:"50%", border:`2px solid ${bc}`, animation:"ripple 1s infinite" }}/>}
          <div style={{ width:52, height:52, borderRadius:"50%", background:playing?`${bc}30`:"rgba(0,0,0,0.6)", border:`2px solid ${playing?bc:"rgba(255,255,255,0.4)"}`, display:"flex", alignItems:"center", justifyContent:"center", transition:"all 0.2s", boxShadow:playing?`0 0 20px ${bc}40`:"none" }}>
            {finished
              ? <Icon name="flip" size={22} color={C.white}/>
              : playing
                ? <div style={{ display:"flex", gap:4 }}><div style={{ width:4, height:18, background:C.white, borderRadius:2 }}/><div style={{ width:4, height:18, background:C.white, borderRadius:2 }}/></div>
                : <div style={{ width:0, height:0, borderLeft:`18px solid ${C.white}`, borderTop:"11px solid transparent", borderBottom:"11px solid transparent", marginLeft:4 }}/>
            }
          </div>
        </div>

        {/* Duration badge */}
        <div style={{ position:"absolute", bottom:10, right:10, background:"rgba(0,0,0,0.6)", borderRadius:4, padding:"2px 7px" }}>
          <span style={{ color:C.white, fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700 }}>
            {playing || playProgress > 0 ? `${fmt(elapsed)} / ${fmt(DURATION)}` : `0:${String(DURATION).padStart(2,"0")}`}
          </span>
        </div>
      </div>

      {/* Progress bar */}
      <div style={{ height:3, background:"rgba(255,255,255,0.1)" }}>
        <div style={{ height:"100%", background:bc, width:`${playProgress}%`, transition:"width 0.05s linear", boxShadow:`0 0 6px ${bc}` }}/>
      </div>
    </div>
  );
};


