const THREAD_REPLIES = [
  { id:1, user:"KeenanC", avatar:"KC", belt:"black", text:"Talk to the coach. Directly, privately, not as a complaint — just 'hey this person's intensity is creating injury risk for others.' A good coach will handle it without drama. If they don't, that tells you something about the gym.", time:"10m", respects:41 },
  { id:2, user:"CompDave", avatar:"CD", belt:"brown", text:"I had this exact situation. I started choosing positions that neutralized his spazzing — top half, back mount. Let him tire himself out. After 3 months he actually calmed down significantly. Sometimes it's just inexperience and it resolves itself.", time:"18m", respects:28 },
  { id:3, user:"GarryTonon", avatar:"GT", belt:"black", verified:true, text:"The spaz problem is almost always a fear response. He's not trying to hurt you — his nervous system is in survival mode. If you can create a dynamic where he feels safe, the spazzing usually drops. Take dominant positions early and hold them calmly.", time:"25m", respects:87 },
  { id:4, user:"RioRoller", avatar:"RR", belt:"purple", text:"Sometimes the answer is just: don't roll with him. You're not obligated to be someone's crash test dummy. There's nothing wrong with saying 'not tonight' when he looks your way.", time:"31m", respects:63 },
];


