const CommunityScreen = ({ sessions=[] }) => {
  const [sort, setSort] = useState("Hot");
  const [activeCategory, setActiveCategory] = useState("All");
  const [threads, setThreads] = useState(SEED_THREADS);
  const [openThread, setOpenThread] = useState(null);
  const [replyText, setReplyText] = useState("");
  const [threadReplies, setThreadReplies] = useState(THREAD_REPLIES);
  const [showNewThread, setShowNewThread] = useState(false);
  const [newTitle, setNewTitle] = useState("");
  const [newBody, setNewBody] = useState("");
  const [newCategory, setNewCategory] = useState("Ask the Room");
  const [communityTab, setCommunityTab] = useState("THREADS");
  const [joined, setJoined] = useState(true); // user already joined by default
  const [showCompleted, setShowCompleted] = useState(false);

  const CATEGORIES = ["All","Ask the Room","Technique Debate","Comp Prep","Injury & Recovery","Gear","Off the Mat"];
  const CAT_COLORS = { "Ask the Room":C.gold, "Technique Debate":C.red, "Comp Prep":C.purple, "Injury & Recovery":C.orange, "Gear":C.teal, "Off the Mat":C.green };
  const SORTS = ["Hot","New","Top"];

  const filtered = threads
    .filter(t => activeCategory==="All" || t.category===activeCategory)
    .sort((a,b) => sort==="Hot" ? (b.hot?1:0)-(a.hot?1:0) : sort==="Top" ? b.respects-a.respects : b.id-a.id);

  // Compute real challenge progress from sessions this week
  const challenge = SEED_CHALLENGES.find(c=>c.active);
  const weekStart = new Date(); weekStart.setDate(weekStart.getDate() - weekStart.getDay()); weekStart.setHours(0,0,0,0);
  const thisWeekSessions = sessions.filter(s => new Date(s.date) >= weekStart);

  const challengeProgress = (() => {
    if(!challenge) return 0;
    if(challenge.goalType==="sessions") return thisWeekSessions.length;
    if(challenge.goalType==="submissions") return thisWeekSessions.reduce((a,s)=>(a+(s.subsCaught?.length||0)),0);
    if(challenge.goalType==="duration") return thisWeekSessions.reduce((a,s)=>(a+(s.duration||0)),0);
    return 0;
  })();
  const progressPct = Math.min(100, (challengeProgress / (challenge?.goal||1)) * 100);
  const isComplete = challengeProgress >= (challenge?.goal||1);

  // Show completion badge when first completed
  useEffect(()=>{
    if(isComplete && joined && !showCompleted) {
      setTimeout(()=>setShowCompleted(true), 200);
    }
  },[isComplete, joined]);

  const submitReply = () => {
    if(!replyText.trim()) return;
    setThreadReplies(r => [...r, { id:r.length+1, user:"CurtyGrappler", avatar:"CG", belt:"blue", text:replyText, time:"just now", respects:0 }]);
    if(openThread) setThreads(ts => ts.map(t => t.id===openThread.id ? {...t, replies:t.replies+1} : t));
    setReplyText("");
  };

  /* ── Challenge Tab ── */
  const ChallengeTab = () => (
    <div style={{ padding:16 }}>
      {/* Active challenge card */}
      {challenge && (
        <div style={{ marginBottom:20 }}>
          <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:10 }}>
            <div style={{ width:6, height:6, borderRadius:"50%", background:C.red, animation:"pulse 2s infinite" }}/>
            <span style={{ color:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:10, letterSpacing:1, fontWeight:700 }}>THIS WEEK'S CHALLENGE</span>
            <span style={{ color:C.muted, fontSize:10, marginLeft:"auto" }}>{challenge.daysLeft}d left</span>
          </div>

          <div style={{ background:C.bgCard, borderRadius:14, border:`1px solid ${isComplete?C.red:C.border}`, overflow:"hidden", boxShadow: isComplete?`0 0 20px ${C.redGlow}`:undefined, transition:"all 0.4s" }}>
            {/* Banner */}
            <div style={{ background:isComplete?`linear-gradient(135deg,${C.red}30,${C.gold}20)`:`linear-gradient(135deg,${C.red}15,transparent)`, padding:"18px 18px 14px", borderBottom:`1px solid ${C.border}` }}>
              <div style={{ display:"flex", alignItems:"flex-start", gap:12 }}>
                <div style={{ fontSize:36, lineHeight:1 }}>{challenge.badge}</div>
                <div style={{ flex:1 }}>
                  <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:17, fontWeight:900, letterSpacing:0.5, marginBottom:4 }}>{challenge.title}</div>
                  <p style={{ color:C.offWhite, fontSize:12, lineHeight:1.6, margin:0 }}>{challenge.description}</p>
                </div>
              </div>
            </div>

            {/* Progress */}
            <div style={{ padding:"14px 18px" }}>
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:8 }}>
                <span style={{ color:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:10, letterSpacing:0.8, fontWeight:700 }}>YOUR PROGRESS</span>
                <span style={{ color:isComplete?C.red:C.white, fontFamily:"'Oswald',sans-serif", fontSize:14, fontWeight:900 }}>
                  {challengeProgress}<span style={{ color:C.muted, fontSize:11, fontWeight:400 }}>/{challenge.goal} {challenge.goalUnit}</span>
                </span>
              </div>
              <div style={{ height:8, background:C.bgElevated, borderRadius:4, overflow:"hidden", marginBottom:10 }}>
                <div style={{ height:"100%", background: isComplete?`linear-gradient(90deg,${C.red},${C.gold})`:`linear-gradient(90deg,${C.red},${C.red}80)`, width:`${progressPct}%`, borderRadius:4, transition:"width 0.6s cubic-bezier(0.34,1.56,0.64,1)", boxShadow:isComplete?`0 0 10px ${C.redGlow}`:undefined }}/>
              </div>

              {/* Step dots */}
              <div style={{ display:"flex", gap:6, marginBottom:14 }}>
                {Array.from({length:challenge.goal},(_,i)=>(
                  <div key={i} style={{ flex:1, height:4, borderRadius:2, background: i < challengeProgress ? C.red : C.bgElevated, transition:"background 0.3s", boxShadow: i < challengeProgress ? `0 0 4px ${C.redGlow}` : undefined }}/>
                ))}
              </div>

              {/* Completion badge */}
              {isComplete && showCompleted && (
                <div style={{ background:`${C.red}15`, border:`1px solid ${C.red}40`, borderRadius:10, padding:"10px 14px", display:"flex", alignItems:"center", gap:10, marginBottom:12 }}>
                  <style>{`@keyframes badgePop{0%{transform:scale(0.5) rotate(-10deg);opacity:0}60%{transform:scale(1.15) rotate(2deg)}100%{transform:scale(1) rotate(0deg);opacity:1}}`}</style>
                  <div style={{ fontSize:26, animation:"badgePop 0.5s ease forwards" }}>{challenge.badge}</div>
                  <div>
                    <div style={{ color:C.red, fontFamily:"'Oswald',sans-serif", fontSize:13, fontWeight:900, letterSpacing:0.5 }}>CHALLENGE COMPLETE!</div>
                    <div style={{ color:C.muted, fontSize:11 }}>You earned the <span style={{ color:C.gold }}>{challenge.badgeName}</span> badge</div>
                  </div>
                </div>
              )}

              {/* Stats row */}
              <div style={{ display:"flex", gap:8 }}>
                <div style={{ flex:1, background:C.bgElevated, borderRadius:8, padding:"9px 10px", textAlign:"center" }}>
                  <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:14, fontWeight:900 }}>{joined ? challenge.participants : challenge.participants}</div>
                  <div style={{ color:C.muted, fontSize:9, fontFamily:"'Oswald',sans-serif", letterSpacing:0.5 }}>JOINED</div>
                </div>
                <div style={{ flex:1, background:C.bgElevated, borderRadius:8, padding:"9px 10px", textAlign:"center" }}>
                  <div style={{ color:C.gold, fontFamily:"'Oswald',sans-serif", fontSize:14, fontWeight:900 }}>{Math.round(challenge.participants * 0.54)}</div>
                  <div style={{ color:C.muted, fontSize:9, fontFamily:"'Oswald',sans-serif", letterSpacing:0.5 }}>ON TRACK</div>
                </div>
                <div style={{ flex:1, background:C.bgElevated, borderRadius:8, padding:"9px 10px", textAlign:"center" }}>
                  <div style={{ color:C.red, fontFamily:"'Oswald',sans-serif", fontSize:14, fontWeight:900 }}>{challenge.daysLeft}d</div>
                  <div style={{ color:C.muted, fontSize:9, fontFamily:"'Oswald',sans-serif", letterSpacing:0.5 }}>REMAINING</div>
                </div>
              </div>

              {/* Join/Leave button */}
              <button onClick={()=>setJoined(j=>!j)}
                style={{ width:"100%", marginTop:12, background:joined?`${C.red}15`:"transparent", border:`1px solid ${joined?C.red:C.border}`, borderRadius:10, padding:"11px 0", cursor:"pointer", fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700, letterSpacing:0.5, color:joined?C.red:C.muted, transition:"all 0.2s" }}>
                {joined ? "✓ JOINED — TAP TO LEAVE" : "JOIN CHALLENGE"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Session log this week */}
      {joined && thisWeekSessions.length > 0 && (
        <div style={{ marginBottom:20 }}>
          <div style={{ color:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:10, letterSpacing:1, fontWeight:700, marginBottom:10 }}>YOUR SESSIONS THIS WEEK</div>
          {thisWeekSessions.map(s => (
            <div key={s.id} style={{ display:"flex", alignItems:"center", gap:10, padding:"8px 0", borderBottom:`1px solid ${C.border}` }}>
              <div style={{ width:8, height:8, borderRadius:"50%", background:SESSION_TYPE_COLOR[s.type]||C.red, flexShrink:0 }}/>
              <span style={{ color:C.white, fontSize:12, flex:1, fontFamily:"'Oswald',sans-serif", fontWeight:700 }}>{s.type}</span>
              <span style={{ color:C.muted, fontSize:11 }}>{s.duration}min</span>
              {(s.subsCaught?.length||0) > 0 && <span style={{ color:C.green, fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700 }}>+{s.subsCaught.length} taps</span>}
              <Icon name="check" size={13} color={C.green}/>
            </div>
          ))}
        </div>
      )}

      {/* Past challenges */}
      <div>
        <div style={{ color:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:10, letterSpacing:1, fontWeight:700, marginBottom:10 }}>PAST CHALLENGES</div>
        {SEED_CHALLENGES.filter(c=>!c.active).map(c => (
          <div key={c.id} style={{ background:C.bgCard, borderRadius:12, border:`1px solid ${C.border}`, padding:"14px 16px", marginBottom:10 }}>
            <div style={{ display:"flex", alignItems:"center", gap:10 }}>
              <div style={{ fontSize:24 }}>{c.badge}</div>
              <div style={{ flex:1 }}>
                <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:13, fontWeight:700 }}>{c.title}</div>
                <div style={{ color:C.muted, fontSize:11, marginTop:2 }}>{c.completedBy} of {c.participants} completed · Badge: <span style={{ color:C.gold }}>{c.badgeName}</span></div>
              </div>
              <div style={{ background:`${C.border}`, height:40, width:1 }}/>
              <div style={{ textAlign:"center", paddingLeft:10 }}>
                <div style={{ color:C.muted, fontSize:10, fontFamily:"'Oswald',sans-serif" }}>RATE</div>
                <div style={{ color:C.gold, fontFamily:"'Oswald',sans-serif", fontSize:14, fontWeight:900 }}>{Math.round((c.completedBy/c.participants)*100)}%</div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  // New thread composer
  if(showNewThread) return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%" }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"14px 16px", borderBottom:`1px solid ${C.border}`, flexShrink:0 }}>
        <button onClick={()=>setShowNewThread(false)} style={{ background:"none", border:"none", cursor:"pointer" }}>
          <Icon name="x" size={20} color={C.offWhite}/>
        </button>
        <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:15, fontWeight:700, letterSpacing:1 }}>NEW THREAD</span>
        <button onClick={()=>setShowNewThread(false)} style={{ background:C.red, border:"none", borderRadius:20, padding:"6px 16px", cursor:"pointer" }}>
          <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>POST</span>
        </button>
      </div>
      <div style={{ flex:1, overflowY:"auto", padding:16 }}>
        <div style={{ marginBottom:14 }}>
          <div style={{ color:C.muted, fontSize:10, fontFamily:"'Oswald',sans-serif", letterSpacing:1, marginBottom:8 }}>CATEGORY</div>
          <div style={{ display:"flex", flexWrap:"wrap", gap:6 }}>
            {CATEGORIES.filter(c=>c!=="All").map(c => {
              const cc = CAT_COLORS[c];
              const active = newCategory===c;
              return <button key={c} onClick={()=>setNewCategory(c)} style={{ background:active?`${cc}20`:"transparent", border:`1px solid ${active?cc:C.border}`, color:active?cc:C.muted, borderRadius:20, padding:"5px 11px", fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700, cursor:"pointer" }}>{c}</button>;
            })}
          </div>
        </div>
        <input value={newTitle} onChange={e=>setNewTitle(e.target.value)} placeholder="Ask a question or start a debate..." style={{ width:"100%", background:"transparent", border:"none", borderBottom:`1px solid ${C.borderLight}`, color:C.white, fontSize:16, fontFamily:"'Oswald',sans-serif", fontWeight:700, padding:"8px 0 10px", marginBottom:14, outline:"none", boxSizing:"border-box" }}/>
        <textarea value={newBody} onChange={e=>setNewBody(e.target.value)} placeholder="Give context. The more specific you are, the better the responses you'll get." style={{ width:"100%", background:"transparent", border:"none", color:C.offWhite, fontSize:13, lineHeight:1.6, resize:"none", outline:"none", minHeight:160, boxSizing:"border-box", fontFamily:"inherit" }}/>
      </div>
    </div>
  );

  // Thread detail
  if(openThread) return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%" }}>
      <div style={{ display:"flex", alignItems:"center", gap:10, padding:"13px 16px", borderBottom:`1px solid ${C.border}`, flexShrink:0 }}>
        <button onClick={()=>setOpenThread(null)} style={{ background:"none", border:"none", cursor:"pointer" }}>
          <Icon name="chevL" size={22} color={C.offWhite}/>
        </button>
        <span style={{ background:`${openThread.cat_color}20`, border:`1px solid ${openThread.cat_color}40`, color:openThread.cat_color, borderRadius:20, padding:"3px 10px", fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700 }}>{openThread.category}</span>
      </div>
      <div style={{ flex:1, overflowY:"auto" }}>
        <div style={{ padding:"16px 16px 14px", borderBottom:`1px solid ${C.border}` }}>
          <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:10 }}>
            <Avatar initials={openThread.avatar} belt={openThread.belt} size={34}/>
            <div>
              <div style={{ display:"flex", alignItems:"center", gap:5 }}>
                <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>{openThread.user}</span>
                {openThread.verified && <Icon name="verified" size={11} color={C.gold}/>}
              </div>
              <span style={{ color:C.muted, fontSize:10 }}>{openThread.timeAgo}</span>
            </div>
          </div>
          <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:15, fontWeight:800, lineHeight:1.4, marginBottom:10 }}>{openThread.title}</div>
          <p style={{ color:C.offWhite, fontSize:13, lineHeight:1.65, margin:"0 0 12px" }}>{openThread.body}</p>
          <div style={{ display:"flex", alignItems:"center", gap:12 }}>
            <button style={{ background:"none", border:"none", cursor:"pointer", display:"flex", alignItems:"center", gap:5 }}>
              <Icon name="fist" size={15} color={C.red}/>
              <span style={{ color:C.red, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>{openThread.respects}</span>
            </button>
            <span style={{ color:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:12 }}>{openThread.replies} replies</span>
          </div>
        </div>
        <div style={{ padding:"12px 16px" }}>
          <div style={{ color:C.muted, fontSize:10, fontFamily:"'Oswald',sans-serif", letterSpacing:1, fontWeight:700, marginBottom:14 }}>REPLIES</div>
          {threadReplies.map(r => (
            <div key={r.id} style={{ display:"flex", gap:10, marginBottom:18 }}>
              <Avatar initials={r.avatar} belt={r.belt} size={32}/>
              <div style={{ flex:1 }}>
                <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:4 }}>
                  <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>{r.user}</span>
                  {r.verified && <Icon name="verified" size={11} color={C.gold}/>}
                  <span style={{ color:C.muted, fontSize:10 }}>{r.time}</span>
                </div>
                <p style={{ color:C.offWhite, fontSize:13, lineHeight:1.6, margin:"0 0 6px" }}>{r.text}</p>
                <div style={{ display:"flex", alignItems:"center", gap:5 }}>
                  <Icon name="fist" size={12} color={C.muted}/>
                  <span style={{ color:C.muted, fontSize:10 }}>{r.respects}</span>
                  <span style={{ color:C.muted, fontSize:10, marginLeft:8, cursor:"pointer" }}>Reply</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
      <div style={{ padding:"10px 16px 16px", borderTop:`1px solid ${C.border}`, display:"flex", gap:10, alignItems:"center", flexShrink:0 }}>
        <Avatar initials="CG" belt="blue" size={30}/>
        <div style={{ flex:1, background:C.bgElevated, borderRadius:20, display:"flex", alignItems:"center", gap:8, padding:"9px 14px" }}>
          <input value={replyText} onChange={e=>setReplyText(e.target.value)} onKeyDown={e=>e.key==="Enter"&&submitReply()} placeholder="Add your take..." style={{ flex:1, background:"none", border:"none", color:C.white, fontSize:13, outline:"none" }}/>
          {replyText && <button onClick={submitReply} style={{ background:"none", border:"none", cursor:"pointer" }}><Icon name="send" size={15} color={C.red}/></button>}
        </div>
      </div>
    </div>
  );

  // Main community screen
  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%" }}>
      {/* Header */}
      <div style={{ padding:"14px 16px 0", borderBottom:`1px solid ${C.border}`, flexShrink:0 }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:12 }}>
          <div>
            <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:18, fontWeight:900, letterSpacing:1 }}>COMMUNITY</div>
            <div style={{ color:C.muted, fontSize:11, marginTop:2 }}>The whole room is listening</div>
          </div>
          {communityTab==="THREADS" && (
            <button onClick={()=>setShowNewThread(true)} style={{ background:C.red, border:"none", borderRadius:22, padding:"9px 14px", cursor:"pointer", display:"flex", alignItems:"center", gap:6, boxShadow:`0 4px 14px ${C.redGlow}` }}>
              <Icon name="plus" size={13} color={C.white}/>
              <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:11, fontWeight:700, letterSpacing:0.5 }}>NEW THREAD</span>
            </button>
          )}
          {communityTab==="CHALLENGE" && (
            <div style={{ display:"flex", alignItems:"center", gap:6 }}>
              {isComplete && <span style={{ fontSize:16 }}>{challenge?.badge}</span>}
              <span style={{ color:isComplete?C.red:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:11, fontWeight:700 }}>
                {isComplete ? "COMPLETE" : `${challengeProgress}/${challenge?.goal}`}
              </span>
            </div>
          )}
        </div>

        {/* Main tabs */}
        <div style={{ display:"flex", borderTop:`1px solid ${C.border}` }}>
          {["THREADS","CHALLENGE"].map(t => (
            <button key={t} onClick={()=>setCommunityTab(t)} style={{ flex:1, background:"none", border:"none", borderBottom:`2px solid ${communityTab===t?C.red:"transparent"}`, color:communityTab===t?C.white:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:11, fontWeight:700, letterSpacing:0.8, padding:"10px 0", cursor:"pointer", transition:"all 0.2s", position:"relative" }}>
              {t}
              {t==="CHALLENGE" && isComplete && joined && (
                <span style={{ position:"absolute", top:6, right:"20%", width:6, height:6, borderRadius:"50%", background:C.red }}/>
              )}
            </button>
          ))}
        </div>
      </div>

      {communityTab==="CHALLENGE" && (
        <div style={{ flex:1, overflowY:"auto" }}>
          <ChallengeTab/>
        </div>
      )}

      {communityTab==="THREADS" && (
        <>
          {/* Pinned challenge teaser */}
          {challenge && joined && (
            <div onClick={()=>setCommunityTab("CHALLENGE")} style={{ margin:"10px 16px 0", background:C.bgCard, borderRadius:10, border:`1px solid ${isComplete?C.red:C.border}40`, padding:"10px 14px", cursor:"pointer", display:"flex", alignItems:"center", gap:10 }}>
              <span style={{ fontSize:20 }}>{challenge.badge}</span>
              <div style={{ flex:1 }}>
                <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>Weekly Challenge: {challenge.title}</div>
                <div style={{ height:3, background:C.bgElevated, borderRadius:2, marginTop:5, overflow:"hidden" }}>
                  <div style={{ height:"100%", width:`${progressPct}%`, background: isComplete?`linear-gradient(90deg,${C.red},${C.gold})`:C.red, borderRadius:2, transition:"width 0.4s" }}/>
                </div>
              </div>
              <span style={{ color:isComplete?C.red:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:11, fontWeight:700 }}>{challengeProgress}/{challenge.goal}</span>
              <Icon name="chevR" size={14} color={C.muted}/>
            </div>
          )}

          <div style={{ display:"flex", gap:0, padding:"10px 16px 0", borderBottom:`1px solid ${C.border}` }}>
            {SORTS.map(s => (
              <button key={s} onClick={()=>setSort(s)} style={{ flex:1, background:"none", border:"none", borderBottom:`2px solid ${sort===s?C.red:"transparent"}`, color:sort===s?C.white:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:11, fontWeight:700, letterSpacing:0.8, padding:"8px 0", cursor:"pointer", transition:"all 0.2s" }}>{s}</button>
            ))}
          </div>
          <div style={{ display:"flex", gap:6, padding:"10px 16px", borderBottom:`1px solid ${C.border}`, overflowX:"auto", scrollbarWidth:"none" }}>
            {CATEGORIES.map(c => {
              const cc = c==="All" ? C.red : CAT_COLORS[c];
              return <Pill key={c} label={c} active={activeCategory===c} onClick={()=>setActiveCategory(c)} color={cc}/>;
            })}
          </div>

          <div style={{ flex:1, overflowY:"auto" }}>
            {filtered.map(thread => (
              <div key={thread.id} onClick={()=>setOpenThread(thread)} style={{ padding:"14px 16px", borderBottom:`1px solid ${C.border}`, cursor:"pointer", transition:"background 0.15s" }}
                onMouseEnter={e=>e.currentTarget.style.background=`${C.red}05`}
                onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:7 }}>
                  <span style={{ background:`${thread.cat_color}15`, border:`1px solid ${thread.cat_color}30`, color:thread.cat_color, borderRadius:20, padding:"2px 9px", fontSize:9, fontFamily:"'Oswald',sans-serif", fontWeight:700, letterSpacing:0.5 }}>{thread.category}</span>
                  {thread.hot && <span style={{ background:`${C.red}15`, color:C.red, borderRadius:20, padding:"2px 7px", fontSize:9, fontFamily:"'Oswald',sans-serif", fontWeight:700 }}>🔥 HOT</span>}
                </div>
                <div style={{ color:C.white, fontSize:14, fontWeight:700, lineHeight:1.4, marginBottom:6, fontFamily:"'Oswald',sans-serif" }}>{thread.title}</div>
                <p style={{ color:C.muted, fontSize:12, lineHeight:1.5, margin:"0 0 10px", overflow:"hidden", display:"-webkit-box", WebkitLineClamp:2, WebkitBoxOrient:"vertical" }}>{thread.body}</p>
                <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                  <Avatar initials={thread.avatar} belt={thread.belt} size={20}/>
                  <span style={{ color:C.muted, fontSize:11, flex:1 }}>{thread.user} · {thread.timeAgo}</span>
                  <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                    <span style={{ color:C.muted, fontSize:11, display:"flex", alignItems:"center", gap:3 }}><Icon name="fist" size={12} color={C.muted}/>{thread.respects}</span>
                    <span style={{ color:C.muted, fontSize:11, display:"flex", alignItems:"center", gap:3 }}><Icon name="comment" size={12} color={C.muted}/>{thread.replies}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
};

/* ─────────────────────────────────────────────
   PROFILE SCREEN
───────────────────────────────────────────── */
const ProfileScreen = ({ sessions, onSettings, savedPosts, userProfile={}, followingIds=[], followerCount=0, onShare, userPosts=[], settings={} }) => {
  const { name="CurtyGrappler", handle="@curtygrappler", belt:initBelt="blue", stripes:initStripes=2, gym="Apex BJJ", bio="" } = userProfile;
  const [belt, setBelt] = useState(initBelt);
  const [profileStripes, setProfileStripes] = useState(initStripes);

  useEffect(()=>{ setBelt(initBelt); },[initBelt]);
  useEffect(()=>{ setProfileStripes(initStripes); },[initStripes]);
  const [prevBelt, setPrevBelt] = useState("blue");
  const [photo, setPhoto] = useState(null);
  const [showPromotion, setShowPromotion] = useState(false);
  const fileRef = useRef();
  const BELTS = ["white","blue","purple","brown","black"];
  const BELT_ORDER = { white:0, blue:1, purple:2, brown:3, black:4 };
  const totalSessions = sessions.length;
  const totalHours = (sessions.reduce((a,s)=>a+s.duration,0)/60).toFixed(1);
  const totalSubs = sessions.reduce((a,s)=>a+(s.subsCaught?.length||0),0);

  const handlePhoto = e => {
    const file = e.target.files?.[0];
    if(file){ const r = new FileReader(); r.onload=ev=>setPhoto(ev.target.result); r.readAsDataURL(file); }
  };

  const handleBeltChange = (b) => {
    if(BELT_ORDER[b] > BELT_ORDER[belt]) {
      setPrevBelt(belt);
      setBelt(b);
      setShowPromotion(true);
    } else {
      setBelt(b);
    }
  };

  const TABS_PROFILE = ["Posts","Saved","Techniques","Comps","Partners"];
  const [profileTab, setProfileTab] = useState("Posts");
  const [partners, setPartners] = useState([
    { id:1, name:"Mike T.", belt:"purple", notes:"Heavy leg lock game. Great to drill guard retention with. Goes hard but controlled.", lastRolled:"2 days ago" },
    { id:2, name:"Jay", belt:"blue", notes:"Explosive wrestler. Use him for anti-wrestling reps. Dangerous double leg.", lastRolled:"1 week ago" },
  ]);
  const [partnerDraft, setPartnerDraft] = useState({ name:"", belt:"blue", notes:"", lastRolled:"" });
  const [showAddPartner, setShowAddPartner] = useState(false);
  const PARTNER_BELTS = ["white","blue","purple","brown","black"];

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%" }}>
      <div style={{ padding:"14px 16px", borderBottom:`1px solid ${C.border}`, display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:16, fontWeight:900, letterSpacing:1 }}>PROFILE</span>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          {settings.privateAccount && (
            <div style={{ display:"flex", alignItems:"center", gap:4, background:`${C.gold}15`, border:`1px solid ${C.gold}40`, borderRadius:12, padding:"3px 8px" }}>
              <Icon name="lock" size={11} color={C.gold}/>
              <span style={{ color:C.gold, fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700, letterSpacing:0.5 }}>PRIVATE</span>
            </div>
          )}
          <button onClick={onSettings} style={{ background:"none", border:"none", cursor:"pointer" }}>
            <Icon name="settings" size={20} color={C.offWhite}/>
          </button>
        </div>
      </div>

      <div style={{ flex:1, overflowY:"auto" }}>
        {/* Profile header */}
        <div style={{ padding:"20px 16px 0" }}>
          <div style={{ display:"flex", gap:16, alignItems:"flex-start", marginBottom:14 }}>
            <div style={{ position:"relative", cursor:"pointer" }} onClick={()=>fileRef.current?.click()}>
              <input ref={fileRef} type="file" accept="image/*" style={{ display:"none" }} onChange={handlePhoto}/>
              <Avatar initials={(name||"G").slice(0,2).toUpperCase()} belt={belt} size={72} photo={photo}/>
              <div style={{ position:"absolute", bottom:0, right:0, width:22, height:22, borderRadius:"50%", background:C.gold, border:`2px solid ${C.bg}`, display:"flex", alignItems:"center", justifyContent:"center" }}>
                <Icon name="camera" size={11} color={C.bg}/>
              </div>
            </div>
            <div style={{ flex:1 }}>
              <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:18, fontWeight:900 }}>{name}</div>
              <div style={{ color:C.muted, fontSize:12, marginTop:2 }}>{handle}</div>
              <div style={{ display:"flex", alignItems:"center", gap:5, marginTop:5 }}>
                <div style={{ width:12, height:6, borderRadius:1, background:BELT_COLOR[belt] }}/>
                <span style={{ color:C.offWhite, fontSize:12, textTransform:"capitalize" }}>{belt} Belt{gym ? ` · ${gym}` : ""}</span>
              </div>
            </div>
          </div>

          <p style={{ color:C.offWhite, fontSize:13, lineHeight:1.6, marginBottom:12 }}>{bio || "Grappler. On the mat and loving it. 🥋"}</p>

          {/* Belt selector */}
          <div style={{ marginBottom:6 }}>
            <div style={{ color:C.muted, fontSize:9, fontFamily:"'Oswald',sans-serif", letterSpacing:1, marginBottom:6 }}>TAP TO UPDATE BELT</div>
            <div style={{ display:"flex", gap:8, marginBottom:8 }}>
              {BELTS.map(b => (
                <button key={b} onClick={()=>handleBeltChange(b)} style={{ flex:1, height:14, borderRadius:3, background:BELT_COLOR[b], border:`2px solid ${belt===b?C.white:"transparent"}`, cursor:"pointer", boxShadow:belt===b?`0 0 8px ${BELT_COLOR[b]}60`:"none", transition:"all 0.2s", position:"relative", overflow:"hidden" }}>
                  {belt===b && [...Array(profileStripes)].map((_,i) => (
                    <div key={i} style={{ position:"absolute", right: 2 + i*8, top:0, width:5, height:"100%", background:"rgba(255,255,255,0.85)", borderRadius:1 }}/>
                  ))}
                </button>
              ))}
            </div>
            {/* Stripe selector */}
            <div style={{ display:"flex", gap:6 }}>
              {[0,1,2,3,4].map(n => (
                <button key={n} onClick={()=>setProfileStripes(n)} style={{ flex:1, borderRadius:6, border:`1px solid ${profileStripes===n?BELT_COLOR[belt]:C.border}`, background:profileStripes===n?`${BELT_COLOR[belt]}15`:"transparent", cursor:"pointer", padding:"5px 0", display:"flex", flexDirection:"column", alignItems:"center", gap:3 }}>
                  <div style={{ position:"relative", width:22, height:7, borderRadius:2, background:BELT_COLOR[belt], overflow:"hidden" }}>
                    {[...Array(n)].map((_,i) => (
                      <div key={i} style={{ position:"absolute", right: 1+i*5, top:0, width:4, height:"100%", background:"rgba(255,255,255,0.85)", borderRadius:1 }}/>
                    ))}
                  </div>
                  <span style={{ color:profileStripes===n?BELT_COLOR[belt]:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:9, fontWeight:700 }}>{n}</span>
                </button>
              ))}
            </div>
            {BELT_ORDER[belt] < 4 && (
              <div style={{ color:C.muted, fontSize:10, marginTop:6 }}>Tap a higher belt to trigger your promotion 🎉</div>
            )}
          </div>

          {/* Stats */}
          <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:1, background:C.border, borderRadius:10, overflow:"hidden", marginBottom:14, marginTop:14 }}>
            {[{v:totalSessions,l:"Sessions"},{v:totalHours+"h",l:"Mat Time"},{v:totalSubs,l:"Taps"},{v:userPosts.length,l:"Posts"},{v:followingIds.length,l:"Following"},{v:followerCount||0,l:"Followers"}].map(({v,l}) => (
              <div key={l} style={{ background:C.bgCard, padding:"12px 8px", textAlign:"center" }}>
                <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:16, fontWeight:900 }}>{v}</div>
                <div style={{ color:C.muted, fontSize:9, fontFamily:"'Oswald',sans-serif", letterSpacing:0.5, marginTop:2 }}>{l}</div>
              </div>
            ))}
          </div>

          {/* Profile sub-tabs */}
          <div style={{ display:"flex", borderBottom:`1px solid ${C.border}` }}>
            {TABS_PROFILE.map(t => (
              <button key={t} onClick={()=>setProfileTab(t)} style={{ flex:1, background:"none", border:"none", borderBottom:`2px solid ${profileTab===t?C.red:"transparent"}`, color:profileTab===t?C.red:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:10, fontWeight:700, letterSpacing:0.5, padding:"10px 0", cursor:"pointer" }}>{t}</button>
            ))}
          </div>
        </div>

        {/* Profile tab content */}
        <div style={{ padding:16 }}>
          {profileTab==="Posts" && (
            userPosts.length > 0 ? (
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
                {userPosts.map(p => (
                  <div key={p.id} style={{ background:C.bgCard, borderRadius:8, padding:10, border:`1px solid ${p.accent||C.border}30`, borderLeft:`3px solid ${p.accent||C.red}` }}>
                    <div style={{ color:p.accent||C.red, fontFamily:"'Oswald',sans-serif", fontSize:9, fontWeight:700, letterSpacing:0.5, marginBottom:4, textTransform:"uppercase" }}>{p.type||"post"}</div>
                    <div style={{ color:C.white, fontSize:11, fontWeight:600, lineHeight:1.4, marginBottom:6 }}>{p.title||p.content?.slice(0,50)}</div>
                    <div style={{ display:"flex", gap:8 }}>
                      <span style={{ color:C.muted, fontSize:10 }}>👊 {fmtN(p.likes||0)}</span>
                      <span style={{ color:C.muted, fontSize:10 }}>💬 {fmtN(p.comments||0)}</span>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div style={{ textAlign:"center", padding:"50px 20px" }}>
                <div style={{ fontSize:36, marginBottom:12 }}>✍️</div>
                <div style={{ color:C.muted, fontSize:13 }}>No posts yet.</div>
                <div style={{ color:C.muted, fontSize:12, marginTop:4 }}>Share a session, technique, or milestone to get started.</div>
              </div>
            )
          )}

          {profileTab==="Saved" && (
            <div>
              {savedPosts?.length > 0 ? savedPosts.map(p => (
                <div key={p.id} style={{ background:C.bgCard, borderRadius:10, padding:"12px 14px", border:`1px solid ${C.border}`, marginBottom:10 }}>
                  <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:10 }}>
                    <div style={{ flex:1 }}>
                      <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:5 }}>
                        <Avatar initials={p.avatar} belt={p.belt} size={24}/>
                        <span style={{ color:C.offWhite, fontFamily:"'Oswald',sans-serif", fontSize:11, fontWeight:700 }}>{p.user}</span>
                        <span style={{ color:C.muted, fontSize:10 }}>{p.timeAgo}</span>
                      </div>
                      {p.title && <div style={{ color:C.white, fontSize:13, fontWeight:700, lineHeight:1.4, marginBottom:4, fontFamily:"'Oswald',sans-serif", borderLeft:`2px solid ${p.accent||C.red}`, paddingLeft:7 }}>{p.title}</div>}
                      <p style={{ color:C.muted, fontSize:12, lineHeight:1.5, margin:"0 0 8px" }}>{p.content.slice(0,100)}...</p>
                      <div style={{ display:"flex", gap:8 }}>
                        <span style={{ color:C.muted, fontSize:10 }}>👊 {fmtN(p.likes)}</span>
                        <span style={{ color:C.muted, fontSize:10 }}>💬 {fmtN(p.comments)}</span>
                      </div>
                    </div>
                    <Icon name="bookmarkF" size={16} color={C.gold}/>
                  </div>
                </div>
              )) : (
                <div style={{ textAlign:"center", padding:"50px 20px" }}>
                  <Icon name="bookmark" size={36} color={C.border}/>
                  <div style={{ color:C.muted, marginTop:12, fontSize:13 }}>No saved posts yet.</div>
                  <div style={{ color:C.muted, fontSize:12, marginTop:4 }}>Tap Save on any post to collect it here.</div>
                </div>
              )}
            </div>
          )}

          {profileTab==="Techniques" && (
            <div>
              {SEED_TECHNIQUES.slice(0,3).map(t => (
                <div key={t.id} style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"10px 0", borderBottom:`1px solid ${C.border}` }}>
                  <div>
                    <div style={{ color:C.white, fontSize:13, fontWeight:600 }}>{t.name}</div>
                    <div style={{ color:C.muted, fontSize:11 }}>{t.position}</div>
                  </div>
                  <div style={{ display:"flex", gap:1 }}>
                    {[1,2,3,4,5].map(s => <span key={s} style={{ fontSize:11, color:s<=t.proficiency?C.gold:C.border }}>★</span>)}
                  </div>
                </div>
              ))}
            </div>
          )}

          {profileTab==="Comps" && (
            <div>
              {SEED_COMPETITIONS.map(c => (
                <div key={c.id} style={{ background:C.bgCard, borderRadius:8, padding:12, border:`1px solid ${C.border}`, marginBottom:8 }}>
                  <div style={{ display:"flex", justifyContent:"space-between" }}>
                    <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>{c.tournament}</span>
                    <span style={{ color:C.gold, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>{c.result}</span>
                  </div>
                  <div style={{ color:C.muted, fontSize:11, marginTop:2 }}>{c.date}</div>
                  <div style={{ display:"flex", gap:4, marginTop:6 }}>
                    {c.matches.map((m,i) => (
                      <div key={i} style={{ background: m.result==="W"?`${C.green}20`:`${C.red}20`, border:`1px solid ${m.result==="W"?C.green:C.red}40`, color: m.result==="W"?C.green:C.red, borderRadius:4, padding:"2px 7px", fontSize:10, fontFamily:"'Oswald',sans-serif", fontWeight:700 }}>{m.result}</div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}

          {profileTab==="Partners" && (
            <div>
              <button onClick={()=>setShowAddPartner(s=>!s)} style={{ width:"100%", background:`${C.red}15`, border:`1px solid ${C.red}30`, borderRadius:10, padding:"12px", cursor:"pointer", marginBottom:14, display:"flex", alignItems:"center", justifyContent:"center", gap:6 }}>
                <Icon name="plus" size={13} color={C.red}/>
                <span style={{ color:C.red, fontFamily:"'Oswald',sans-serif", fontSize:11, fontWeight:700 }}>ADD TRAINING PARTNER</span>
              </button>

              {showAddPartner && (
                <div style={{ background:C.bgCard, borderRadius:12, border:`1px solid ${C.border}`, padding:14, marginBottom:14 }}>
                  <input value={partnerDraft.name} onChange={e=>setPartnerDraft(d=>({...d,name:e.target.value}))}
                    placeholder="Name or nickname..." style={{ width:"100%", background:C.bgElevated, border:`1px solid ${C.border}`, borderRadius:8, color:C.white, fontSize:12, padding:"9px 11px", outline:"none", boxSizing:"border-box", marginBottom:8 }}/>
                  <div style={{ display:"flex", gap:5, marginBottom:8 }}>
                    {PARTNER_BELTS.map(b => (
                      <button key={b} onClick={()=>setPartnerDraft(d=>({...d,belt:b}))}
                        style={{ flex:1, height:28, borderRadius:6, background:BELT_COLOR[b], border:`2px solid ${partnerDraft.belt===b?C.white:"transparent"}`, cursor:"pointer", opacity:partnerDraft.belt===b?1:0.5, transition:"all 0.2s" }}/>
                    ))}
                  </div>
                  <textarea value={partnerDraft.notes} onChange={e=>setPartnerDraft(d=>({...d,notes:e.target.value}))}
                    placeholder="Their game, what you drill with them, things to watch for..." rows={2}
                    style={{ width:"100%", background:C.bgElevated, border:`1px solid ${C.border}`, borderRadius:8, color:C.offWhite, fontSize:12, lineHeight:1.6, padding:"9px 11px", outline:"none", resize:"none", boxSizing:"border-box", fontFamily:"inherit", marginBottom:8 }}/>
                  <input value={partnerDraft.lastRolled} onChange={e=>setPartnerDraft(d=>({...d,lastRolled:e.target.value}))}
                    placeholder="Last rolled (e.g. today, 3 days ago)..." style={{ width:"100%", background:C.bgElevated, border:`1px solid ${C.border}`, borderRadius:8, color:C.white, fontSize:12, padding:"9px 11px", outline:"none", boxSizing:"border-box", marginBottom:10 }}/>
                  <button onClick={()=>{
                    if(!partnerDraft.name.trim()) return;
                    setPartners(p=>[...p,{...partnerDraft,id:Date.now()}]);
                    setPartnerDraft({name:"",belt:"blue",notes:"",lastRolled:""});
                    setShowAddPartner(false);
                  }} disabled={!partnerDraft.name.trim()}
                    style={{ width:"100%", background:partnerDraft.name.trim()?C.red:`${C.red}40`, border:"none", borderRadius:10, padding:"11px", cursor:partnerDraft.name.trim()?"pointer":"not-allowed" }}>
                    <span style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>SAVE PARTNER</span>
                  </button>
                </div>
              )}

              {partners.map(p => (
                <div key={p.id} style={{ background:C.bgCard, borderRadius:12, border:`1px solid ${C.border}`, padding:"12px 14px", marginBottom:10 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom: p.notes?8:0 }}>
                    <div style={{ width:38, height:38, borderRadius:10, background:`${BELT_COLOR[p.belt]||C.muted}20`, border:`2px solid ${BELT_COLOR[p.belt]||C.muted}`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                      <div style={{ width:18, height:7, borderRadius:1, background:BELT_COLOR[p.belt]||C.muted }}/>
                    </div>
                    <div style={{ flex:1 }}>
                      <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:13, fontWeight:800 }}>{p.name}</div>
                      <div style={{ color:C.muted, fontSize:10, textTransform:"capitalize" }}>{p.belt} belt{p.lastRolled ? ` · Last rolled: ${p.lastRolled}` : ""}</div>
                    </div>
                    <button onClick={()=>setPartners(ps=>ps.filter(x=>x.id!==p.id))} style={{ background:"none", border:"none", cursor:"pointer", color:C.muted, fontSize:18, lineHeight:1 }}>×</button>
                  </div>
                  {p.notes && <p style={{ color:C.offWhite, fontSize:12, lineHeight:1.5, margin:0 }}>{p.notes}</p>}
                </div>
              ))}
              {partners.length === 0 && !showAddPartner && (
                <div style={{ textAlign:"center", padding:"40px 20px", color:C.muted, fontSize:12 }}>No training partners yet.<br/>Add the people you roll with.</div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Belt Promotion overlay */}
      {showPromotion && <BeltPromotion fromBelt={prevBelt} toBelt={belt} onClose={()=>setShowPromotion(false)} onShare={onShare} userProfile={userProfile}/>}
    </div>
  );
};

/* ─────────────────────────────────────────────
   SHARE SESSION PROMPT
───────────────────────────────────────────── */
const ShareSessionPrompt = ({ session, onShare, onSkip, userProfile={} }) => {
  const { name="CurtyGrappler", handle="@curtygrappler", belt="blue" } = userProfile;
  const initials = name.slice(0,2).toUpperCase();
  const hrs = Math.floor((session.duration||0)/60);
  const mins = (session.duration||0) % 60;
  const durationStr = hrs > 0 ? `${hrs}h ${mins}m` : `${mins}m`;
  const subsStr = session.subsCaught?.length ? ` ${session.subsCaught.length} tap${session.subsCaught.length>1?"s":""}.` : "";
  const autoTitle = session.intention
    ? session.intention.slice(0,60) + (session.intention.length>60?"…":"")
    : `${session.type} session — ${durationStr} on the mat`;
  const autoBody = [
    `${durationStr} · ${session.type} · ${session.rounds} rounds${session.gym?` · ${session.gym}`:""}`,
    session.intention ? `\nFocus: ${session.intention}` : "",
    session.reflection ? `\n\n${session.reflection}` : "",
    subsStr ? `\nCaught: ${session.subsCaught.join(", ")}` : "",
  ].filter(Boolean).join("").trim();

  const [title, setTitle] = useState(autoTitle);
  const [body, setBody] = useState(autoBody);

  const typeColors = { technique:C.red, insight:C.gold, story:C.teal, milestone:C.purple };

  return (
    <div style={{ position:"absolute", inset:0, background:"rgba(0,0,0,0.85)", zIndex:300, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:20 }}>
      <style>{`@keyframes promptIn{from{transform:translateY(30px);opacity:0}to{transform:translateY(0);opacity:1}}`}</style>
      <div style={{ background:C.bgCard, borderRadius:16, width:"100%", maxWidth:380, border:`1px solid ${C.border}`, animation:"promptIn 0.3s ease", overflow:"hidden" }}>
        {/* Header */}
        <div style={{ padding:"16px 18px 12px", borderBottom:`1px solid ${C.border}` }}>
          <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
            <div style={{ width:32, height:32, borderRadius:"50%", background:`${C.red}20`, border:`1px solid ${C.red}40`, display:"flex", alignItems:"center", justifyContent:"center" }}>
              <Icon name="edit" size={14} color={C.red}/>
            </div>
            <div>
              <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:14, fontWeight:900, letterSpacing:0.5 }}>SHARE TO FEED?</div>
              <div style={{ color:C.muted, fontSize:11 }}>Turn this session into a post</div>
            </div>
          </div>
        </div>

        {/* Preview / editable */}
        <div style={{ padding:"14px 18px" }}>
          <div style={{ display:"flex", gap:8, marginBottom:10 }}>
            <Avatar initials={initials} belt={belt} size={32}/>
            <div>
              <div style={{ color:C.white, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700 }}>{name}</div>
              <span style={{ background:`${C.purple}20`, border:`1px solid ${C.purple}40`, color:C.purple, borderRadius:3, padding:"1px 5px", fontSize:9, fontFamily:"'Oswald',sans-serif", fontWeight:700 }}>MILESTONE</span>
            </div>
          </div>

          <input value={title} onChange={e=>setTitle(e.target.value)}
            style={{ width:"100%", background:"transparent", border:"none", borderBottom:`1px solid ${C.borderLight}`, color:C.white, fontSize:14, fontFamily:"'Oswald',sans-serif", fontWeight:700, padding:"4px 0 8px", outline:"none", marginBottom:10, boxSizing:"border-box" }}/>

          <textarea value={body} onChange={e=>setBody(e.target.value)} rows={4}
            style={{ width:"100%", background:C.bgElevated, border:`1px solid ${C.border}`, borderRadius:8, color:C.offWhite, fontSize:12, lineHeight:1.6, padding:"8px 10px", outline:"none", resize:"none", boxSizing:"border-box" }}/>

          {/* Session stat pills */}
          <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginTop:10 }}>
            {[`⏱ ${durationStr}`, `🥋 ${session.type}`, `${session.rounds} rounds`, ...(session.subsCaught||[]).map(s=>`✓ ${s}`)].map((t,i) => (
              <span key={i} style={{ background:`${C.red}15`, border:`1px solid ${C.red}30`, color:C.offWhite, borderRadius:20, padding:"3px 9px", fontSize:10, fontFamily:"'Oswald',sans-serif" }}>{t}</span>
            ))}
          </div>
        </div>

        {/* Actions */}
        <div style={{ display:"flex", gap:0, borderTop:`1px solid ${C.border}` }}>
          <button onClick={onSkip} style={{ flex:1, background:"none", border:"none", borderRight:`1px solid ${C.border}`, color:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700, padding:"14px 0", cursor:"pointer", letterSpacing:0.5 }}>SKIP</button>
          <button onClick={()=>onShare({
            id:Date.now(), user:name, belt:belt, handle:handle, avatar:initials,
            timeAgo:"just now", verified:false, type:"milestone",
            title:title.trim(), content:body.trim(),
            tags:["training","bjjlife",session.type.toLowerCase()],
            likes:0, comments:0, shares:0, saves:0, liked:false, saved:false, accent:C.purple
          })} style={{ flex:1, background:`${C.red}15`, border:"none", color:C.red, fontFamily:"'Oswald',sans-serif", fontSize:12, fontWeight:700, padding:"14px 0", cursor:"pointer", letterSpacing:0.5 }}>POST IT</button>
        </div>
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────────
   APP SHELL
───────────────────────────────────────────── */
export default function App() {
  const [showOnboarding, setShowOnboarding] = useState(true);
  const [activeTab, setActiveTab] = useState("home");
  const [sessions, setSessions] = useState(SEED_SESSIONS);
  const [savedPostIds, setSavedPostIds] = useState(
    SEED_POSTS.filter(p=>p.saved).map(p=>p.id)
  );
  const [showLog, setShowLog] = useState(false);
  const [showCreate, setShowCreate] = useState(false);
  const [showNotifs, setShowNotifs] = useState(false);
  const [showDMs, setShowDMs] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [appSettings, setAppSettings] = useState({
    pushLikes:true, pushComments:true, pushFollows:true, pushMessages:true,
    privateAccount:false, showBelt:true, showGym:true, showWeight:false,
    darkMode:true, autoplayVideo:false, haptics:true,
  });
  const toggleSetting = k => setAppSettings(s => ({...s, [k]:!s[k]}));
  const [userPosts, setUserPosts] = useState([]);
  const [storyIndex, setStoryIndex] = useState(null);
  const [followingIds, setFollowingIds] = useState(["@garrytonon", "@keenan_cornelius"]);
  const [weightLog, setWeightLog] = useState([]);
  const [sharePromptSession, setSharePromptSession] = useState(null);
  const [userProfile, setUserProfile] = useState({
    name: "CurtyGrappler",
    handle: "@curtygrappler",
    belt: "blue",
    stripes: 2,
    gym: "Apex BJJ",
    bio: "Grappler. Builder. Perpetual white belt at life. Training since 2019. \"Pressure is a privilege.\" 🥋",
  });
  const unreadNotifs = SEED_NOTIFICATIONS.filter(n=>!n.read).length;
  const unreadDMs = SEED_DM_THREADS.reduce((a,t)=>a+t.unread,0);

  const handleSaveToggle = (id, saved) => {
    setSavedPostIds(prev => saved ? [...prev, id] : prev.filter(x=>x!==id));
  };

  const handleNewPost = (post) => {
    setUserPosts(prev => [post, ...prev]);
  };

  const handleFollow = (handle) => {
    setFollowingIds(prev => prev.includes(handle) ? prev.filter(h=>h!==handle) : [...prev, handle]);
  };

  const savedPosts = SEED_POSTS.filter(p => savedPostIds.includes(p.id));

  const NAV = [
    { id:"home", icon:"home", label:"HOME" },
    { id:"search", icon:"compass", label:"DISCOVER" },
    { id:"diary", icon:"book", label:"DIARY" },
    { id:"community", icon:"comment", label:"COMMUNITY" },
    { id:"profile", icon:"user", label:"PROFILE" },
  ];

  return (
    <div style={{ fontFamily:"'Georgia',serif", background:C.bg, color:C.white, width:"100%", maxWidth:420, height:"100vh", maxHeight:860, margin:"0 auto", display:"flex", flexDirection:"column", position:"relative", overflow:"hidden", borderRadius:window.innerWidth>500?16:0, boxShadow:window.innerWidth>500?"0 20px 60px rgba(0,0,0,0.8)":"none" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Oswald:wght@300;400;500;600;700;800;900&display=swap');
        *{box-sizing:border-box;-webkit-tap-highlight-color:transparent}
        ::-webkit-scrollbar{display:none}
        input::placeholder,textarea::placeholder{color:#4A4A4A}
        select option{background:#161616}
        @keyframes slideUp{from{transform:translateY(20px);opacity:0}to{transform:translateY(0);opacity:1}}
      `}</style>

      {/* Top Header */}
      <div style={{ background:C.bg, borderBottom:`1px solid ${C.border}`, padding:"12px 16px", display:"flex", alignItems:"center", justifyContent:"space-between", flexShrink:0 }}>
        <div style={{ fontFamily:"'Oswald',sans-serif", fontSize:16, fontWeight:900, letterSpacing:2, color:C.red }}>DIARY OF A GRAPPLER</div>
        <div style={{ display:"flex", gap:4 }}>
          <button onClick={()=>setShowCreate(true)} style={{ background:"none", border:"none", cursor:"pointer", padding:6, position:"relative" }}>
            <Icon name="edit" size={20} color={C.offWhite}/>
          </button>
          <button onClick={()=>setShowNotifs(true)} style={{ background:"none", border:"none", cursor:"pointer", padding:6, position:"relative" }}>
            <Icon name="bell" size={20} color={C.offWhite}/>
            <Badge count={unreadNotifs}/>
          </button>
          <button onClick={()=>setShowDMs(true)} style={{ background:"none", border:"none", cursor:"pointer", padding:6, position:"relative" }}>
            <Icon name="mail" size={20} color={C.offWhite}/>
            <Badge count={unreadDMs}/>
          </button>
        </div>
      </div>

      {/* Screen Content */}
      <div style={{ flex:1, overflow:"hidden", display:"flex", flexDirection:"column" }}>
        {activeTab==="home" && <HomeScreen onCreatePost={()=>setShowCreate(true)} savedPostIds={savedPostIds} onSaveToggle={handleSaveToggle} extraPosts={userPosts} onOpenStory={(i)=>setStoryIndex(i)} followingIds={followingIds} onFollow={handleFollow}/>}
        {activeTab==="search" && <DiscoverScreen followingIds={followingIds} onFollow={handleFollow} userPosts={userPosts}/>}
        {activeTab==="community" && <CommunityScreen sessions={sessions}/>}
        {activeTab==="diary" && <DiaryScreen sessions={sessions} onLogSession={()=>setShowLog(true)} weightLog={weightLog} onWeightLog={kg=>{const now=new Date();setWeightLog(prev=>[...prev,{w:`W${prev.length+1}`,kg,date:now}]);}} settings={appSettings}/>}
        {activeTab==="profile" && <ProfileScreen sessions={sessions} onSettings={()=>setShowSettings(true)} savedPosts={savedPosts} userProfile={userProfile} followingIds={followingIds} followerCount={followingIds.length > 0 ? Math.max(0, followingIds.length * 12 + 3) : 0} onShare={post=>{ handleNewPost(post); setActiveTab("home"); }} userPosts={userPosts} settings={appSettings}/>}
      </div>

      {/* Bottom Nav */}
      <nav style={{ background:C.bgCard, borderTop:`1px solid ${C.border}`, display:"flex", alignItems:"center", padding:"0 0 env(safe-area-inset-bottom,0)", flexShrink:0, position:"relative", overflow:"visible" }}>
        {NAV.map(tab => {
          const active = activeTab===tab.id;
          if(tab.id==="diary") return (
            <div key="diary" style={{ flex:1, display:"flex", alignItems:"center", justifyContent:"center", position:"relative" }}>
              <button onClick={()=>setActiveTab("diary")} style={{ background:"none", border:"none", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:3, padding:"4px 0 8px", position:"relative", width:"100%" }}>
                <div style={{ width:44, height:44, borderRadius:"50%", background: active ? C.red : C.bgElevated, border:`2px solid ${active?C.red:C.borderLight}`, display:"flex", alignItems:"center", justifyContent:"center", boxShadow: active ? `0 4px 16px ${C.redGlow}` : `0 2px 8px rgba(0,0,0,0.4)`, transition:"all 0.2s", marginTop:-22, zIndex:1 }}>
                  <Icon name="book" size={18} color={active?C.white:C.muted}/>
                </div>
                <span style={{ color:active?C.red:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:8, letterSpacing:0.5, fontWeight:active?700:400 }}>DIARY</span>
              </button>
            </div>
          );
          return (
            <button key={tab.id} onClick={()=>setActiveTab(tab.id)} style={{ flex:1, background:"none", border:"none", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:3, padding:"12px 0 10px", position:"relative" }}>
              {active && <div style={{ position:"absolute", top:0, left:"25%", right:"25%", height:2, borderRadius:1, background:C.red }}/>}
              <Icon name={tab.icon} size={20} color={active?C.red:C.muted}/>
              <span style={{ color:active?C.red:C.muted, fontFamily:"'Oswald',sans-serif", fontSize:8, letterSpacing:0.5, fontWeight:active?700:400 }}>{tab.label}</span>
            </button>
          );
        })}
      </nav>

      {/* Overlays */}
      {showLog && <LogSessionSheet onClose={()=>setShowLog(false)} onSave={s=>{setSessions(prev=>[s,...prev]);setShowLog(false);setSharePromptSession(s);}}/>}
      {showCreate && <CreatePost onClose={()=>setShowCreate(false)} onPost={handleNewPost}/>}
      {showNotifs && <NotificationsScreen onClose={()=>setShowNotifs(false)}/>}
      {showDMs && <DMsScreen onClose={()=>setShowDMs(false)}/>}
      {showSettings && <SettingsScreen onClose={()=>setShowSettings(false)} settings={appSettings} onToggle={toggleSetting} userProfile={userProfile} onEditProfile={p=>setUserProfile(prev=>({...prev,...p}))}/>}
      {storyIndex !== null && <StoryViewer stories={SEED_STORIES} startIndex={storyIndex} onClose={()=>setStoryIndex(null)}/>}

      {sharePromptSession && <ShareSessionPrompt session={sharePromptSession} userProfile={userProfile} onSkip={()=>setSharePromptSession(null)} onShare={post=>{ handleNewPost(post); setSharePromptSession(null); setActiveTab("home"); }}/>}

      {/* Onboarding — rendered last so it sits on top */}
      {showOnboarding && <OnboardingFlow onComplete={(profileData)=>{
        if(profileData) {
          setUserProfile({
            name: profileData.name || "Grappler",
            handle: profileData.handle ? (profileData.handle.startsWith("@") ? profileData.handle : "@"+profileData.handle) : "@grappler",
            belt: profileData.belt || "white",
            stripes: profileData.stripes || 0,
            gym: profileData.gym || "",
            bio: `${profileData.belt ? profileData.belt.charAt(0).toUpperCase()+profileData.belt.slice(1)+' belt' : 'Grappler'}${profileData.gym ? ' · '+profileData.gym : ''}. On the mat and loving it. 🥋`,
          });
          if(profileData.followed?.length) {
            setFollowingIds(prev => [...new Set([...prev, ...profileData.followed])]);
          }
        }
        setShowOnboarding(false);
      }}/>}
    </div>
  );
}
